import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Пошук надійних модів","description":"Інструкція із пошуку модів Fabric за допомогою надійних джерел.","frontmatter":{"title":"Пошук надійних модів","description":"Інструкція із пошуку модів Fabric за допомогою надійних джерел.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"uk_ua/1.20.4/players/finding-mods.md","filePath":"versions/1.20.4/translated/uk_ua/players/finding-mods.md","lastUpdated":1739538073000}`);var a={name:`uk_ua/1.20.4/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Пошук надійних модів <a class="header-anchor" href="#h1" aria-label="Permalink to “Пошук надійних модів”">​</a></h1><p>По-перше, довіра суб&#39;єктивна, і ви завжди повинні керуватися власним судженням, завантажуючи моди. Однак є деякі речі, які ви можете зробити, щоб допомогти вам знайти надійні моди.</p><h2 id="_1-використовуите-джерело-яке-заслуговує-довіри" tabindex="-1">1. Використовуйте джерело, яке заслуговує довіри <a class="header-anchor" href="#_1-використовуите-джерело-яке-заслуговує-довіри" aria-label="Permalink to “1. Використовуйте джерело, яке заслуговує довіри”">​</a></h2><p>Більшість авторів публікують свої моди на <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> та <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Ці веб-сайти перевіряють, чи моди є такими, якими вони є, і що вони не містять шкідливого коду. Ви також можете повідомити про шкідливі моди на цих веб-сайтах, і вони відносно швидко вживуть заходів.</p><h2 id="_2-перевірте-в-інших" tabindex="-1">2. Перевірте в інших! <a class="header-anchor" href="#_2-перевірте-в-інших" aria-label="Permalink to “2. Перевірте в інших!”">​</a></h2><p>Якщо ви завантажуєте мод з джерела, яке, як відомо, не заслуговує довіри, вам слід перевірити в інших, чи завантажували вони модифікацію раніше з того місця, звідки ви завантажуєте, і чи виникали у них проблеми з цим.</p><p>Якщо ви сумніваєтесь, ви завжди можете запитати в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Діскорд сервері Fabric</a> в каналі <code>#player-support</code>.</p><h2 id="_3-уникаите-поширених-саитів-з-вірусами" tabindex="-1">3. Уникайте поширених сайтів з вірусами! <a class="header-anchor" href="#_3-уникаите-поширених-саитів-з-вірусами" aria-label="Permalink to “3. Уникайте поширених сайтів з вірусами!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Подібні сайти можуть бути не очевидними для всіх. Якщо ви не впевнені, ви можете запитити думки інших або покладатися лише на перевірені джерела, такі як Modrinth та Curseforge.</p></div><p>Існує багато веб-сайтів, які стверджують, що мають моди для Minecraft, але насправді це лише сайти з вірусами. Вам слід оминати подібні сайти.</p><p>Ви можете використовувати антивіруси або вебсайти, такі як <a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> або <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> щоб перевіряти завантажені моди. Але не покладайтеся повністю на них, тому що вони не завжди коректні.</p><p>Знову ж таки, якщо ви сумніваєтеся, ви можете запитати в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Діскорд сервері Fabric</a> в каналі <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};